import{_ as a,o as i,c as o,a0 as s}from"./chunks/framework.ECMusB9M.js";const m=JSON.parse('{"title":"1. Objetivos","description":"","frontmatter":{"layout":"default","title":"1. Objetivos"},"headers":[],"relativePath":"01_objetivos.md","filePath":"01_objetivos.md"}'),n={name:"01_objetivos.md"};function t(r,e,l,c,p,d){return i(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_1-objetivos-de-marketing" tabindex="-1">1. Objetivos de Marketing <a class="header-anchor" href="#_1-objetivos-de-marketing" aria-label="Permalink to &quot;1. Objetivos de Marketing&quot;">​</a></h1><h2 id="_1-1-objetivos-generales" tabindex="-1">1.1. Objetivos generales <a class="header-anchor" href="#_1-1-objetivos-generales" aria-label="Permalink to &quot;1.1. Objetivos generales&quot;">​</a></h2><p>Queremos crear una aplicación que ayude al bienestar mental de los pacientes mediante un sistema de seguimiento que permita centralizar sus datos en un único lugar de forma accesible y segura. Los datos solo serán accesibles para el propio paciente y para su psicólogo o terapeuta de SEMBREM.</p><p>Asimismo, queremos que dichos profesionales puedan acceder a la información de sus pacientes para realizar un seguimiento de su evolución y mejorar la calidad de la intervención terapéutica.</p><p>De forma estratégica, pretendemos:</p><ul><li>Comprobar la viabilidad de un modelo de negocio orientado a profesionales de la salud mental.</li><li>Evaluar la viabilidad del proyecto dentro de SEMBREM y analizar su posible expansión a otros profesionales fuera de la organización.</li><li>Desarrollar un servicio profesional de apoyo terapéutico digital que complemente la atención presencial.</li></ul><h2 id="_1-2-objetivos-especificos" tabindex="-1">1.2. Objetivos específicos <a class="header-anchor" href="#_1-2-objetivos-especificos" aria-label="Permalink to &quot;1.2. Objetivos específicos&quot;">​</a></h2><h3 id="captacion-de-psicologos" tabindex="-1">Captación de psicólogos <a class="header-anchor" href="#captacion-de-psicologos" aria-label="Permalink to &quot;Captación de psicólogos&quot;">​</a></h3><p>Conseguir que al menos 10 psicólogos pertenecientes a SEMBREM utilicen activamente la aplicación durante los tres primeros meses tras su lanzamiento.</p><p>Se considerará uso activo cuando el profesional registre pacientes en la plataforma y consulte su información de forma periódica.</p><h3 id="captacion-de-pacientes" tabindex="-1">Captación de pacientes <a class="header-anchor" href="#captacion-de-pacientes" aria-label="Permalink to &quot;Captación de pacientes&quot;">​</a></h3><p>Conseguir que al menos 100 pacientes utilicen activamente la aplicación durante los tres primeros meses tras su lanzamiento.</p><p>Se considerará uso activo cuando el paciente registre episodios o seguimientos y consulte su información de forma periódica.</p><h3 id="conversion-a-pago" tabindex="-1">Conversión a pago <a class="header-anchor" href="#conversion-a-pago" aria-label="Permalink to &quot;Conversión a pago&quot;">​</a></h3><p>Conseguir que al menos un 40% de los psicólogos que utilicen activamente la aplicación durante los tres primeros meses (periodo en el que se ofrecerá una promoción gratuita) realicen la conversión al plan de pago una vez finalizada dicha promoción.</p>',15)])])}const b=a(n,[["render",t]]);export{m as __pageData,b as default};
